```class Solution {
public:
    long long waysToBuyPensPencils(int total, int cost1, int cost2) {
        long long ways = 0;
        for (int pens = 0; pens * cost1 <= total; pens++) {
            int pencils = total - pens * cost1;
            if (pencils >= 0) {
                ways += pencils / cost2 + 1;
            }
        }
        return ways;
    }
};```
